from checkers.board import Board
from checkers.player import HumanPlayer

class Game:
    def __init__(self):
        self.board = Board()
        self.players = {'red': HumanPlayer('red'), 'black': HumanPlayer('black')}
        self.current_player = 'red'

    def switch_turn(self):
        self.current_player = 'black' if self.current_player == 'red' else 'red'

    def get_current_player_moves(self):
        return self.players[self.current_player].get_valid_moves(self.board)

    def make_move(self, from_pos, to_pos):
        self.players[self.current_player].make_move(self.board, from_pos, to_pos)
        self.switch_turn()

    def run(self):
        while True:
            self.board.draw()
            moves = self.get_current_player_moves()
            if not moves:
                print(f"Player {self.current_player} has no valid moves. Game over.")
                break
            from_pos = input(f"Player {self.current_player}, enter your move (e.g., 1-2): ")
            to_pos = input("Enter the destination position: ")
            self.make_move(from_pos.split('-'), to_pos)

if __name__ == "__main__":
    game = Game()
    game.run()
