# checkers_game/main.py

def initialize_board():
    board = [['.' for _ in range(8)] for _ in range(8)]
    for i in range(3):
        for j in range((i % 2) + 1, 8, 2):
            board[i][j] = 'W'
    for i in range(5, 8):
        for j in range((i % 2) + 1, 8, 2):
            board[i][j] = 'B'
    return board

def print_board(board):
    print("   A B C D E F G H")
    for i, row in enumerate(board):
        print(f"{7-i} {row}")

def is_valid_move(board, start, end):
    x1, y1 = start
    x2, y2 = end
    if board[x1][y1] == '.' or (x1 == x2 and y1 == y2):
        return False
    if abs(x2 - x1) != 1 or abs(y2 - y1) not in [1, 2]:
        return False
    if board[x2][y2] != '.':
        return False
    if abs(board[x1][y1]) == 2 and (abs(x2 - x1) == 1):
        return False
    return True

def make_move(board, start, end):
    x1, y1 = start
    x2, y2 = end
    board[x2][y2] = board[x1][y1]
    board[x1][y1] = '.'
    if abs(y2 - y1) == 2:
        capture_piece(board, (x1 + (x2 - x1) // 2), (y1 + (y2 - y1) // 2))
    return board

def capture_piece(board, x, y):
    board[x][y] = '.'

def check_win(board):
    white_pieces = sum(row.count('W') for row in board)
    black_pieces = sum(row.count('B') for row in board)
    if white_pieces == 0:
        return "Black wins"
    elif black_pieces == 0:
        return "White wins"
    else:
        return None

def check_draw(board):
    # This is a simple heuristic check and can be expanded
    if 'w' not in ''.join(board) or 'b' not in ''.join(board):
        return True
    return False

def main():
    board = initialize_board()
    current_player = 'W'
    while True:
        print_board(board)
        move = input(f"Player {current_player}, enter your move (e.g., A1-B2): ").upper()
        start, end = (int(move[1]) - 1, ord(move[0]) - ord('A')), (int(move[-2]) - 1, ord(move[-1]) - ord('A'))
        if is_valid_move(board, start, end):
            board = make_move(board, start, end)
            winner = check_win(board)
            if winner:
                print_board(board)
                print(winner)
                break
            draw = check_draw(board)
            if draw:
                print_board(board)
                print("It's a draw!")
                break
            current_player = 'B' if current_player == 'W' else 'W'
        else:
            print("Invalid move. Please try again.")

if __name__ == "__main__":
    main()
```

